// FilterForm — typed Inspector form for graph nodes whose `type` is
// "filter". Loads the option schema for `def.filter` from the backend
// and renders one labelled control per AVOption, with type-aware
// widgets (number inputs with min/max for numerics, bool selects, and
// dropdowns for options that declare named constants — e.g. trim's
// units enum, scale's flags).
//
// Editing model matches EncoderForm: every value is stored as a string
// in `def.params`. Empty string ⇒ remove the key entirely so the
// filter falls back to libavfilter's built-in default.

import { useEffect, useMemo, useState } from 'react';
import type { NodeDef } from '../lib/jobTypes';
import { fetchFilterInfo, type FilterOption, type FilterOptionsInfo } from '../lib/filterSchema';
import { OptionControl } from './controls/OptionControl';
import { AudioChannelForm, AUDIO_ROUTING_FILTERS } from './AudioChannelForm';
import { FileBrowser } from './FileBrowser';

interface Props {
  def: NodeDef;
  onChange: (next: NodeDef) => void;
  /** Upstream-pad variable bindings forwarded to expression inputs. */
  padHints?: Record<string, number>;
}

export function FilterForm({ def, onChange, padHints }: Props) {
  const filter = def.filter ?? '';
  const [info, setInfo] = useState<FilterOptionsInfo | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [search, setSearch] = useState('');

  useEffect(() => {
    // Audio routing filters are handled by AudioChannelForm — no AVOptions needed.
    if (!filter || AUDIO_ROUTING_FILTERS.has(filter)) {
      setInfo(null);
      setError(null);
      return;
    }
    setLoading(true);
    setError(null);
    let cancelled = false;
    fetchFilterInfo(filter)
      .then((i) => {
        if (!cancelled) setInfo(i);
      })
      .catch((e: Error) => {
        if (!cancelled) {
          setError(e.message);
          setInfo(null);
        }
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });
    return () => {
      cancelled = true;
    };
  }, [filter]);

  const setParam = (key: string, value: string) => {
    const next = { ...(def.params ?? {}) };
    if (value === '') delete next[key];
    else next[key] = value;
    onChange({ ...def, params: next });
  };

  const getParam = (key: string): string => {
    const v = def.params?.[key];
    return v === undefined || v === null ? '' : String(v);
  };

  const visible = useMemo(() => {
    if (!info) return [];
    const q = search.trim().toLowerCase();
    if (!q) return info.options;
    return info.options.filter(
      (o) =>
        o.name.toLowerCase().includes(q) ||
        (o.help ?? '').toLowerCase().includes(q),
    );
  }, [info, search]);

  if (!filter) {
    return (
      <div className="empty" style={{ fontSize: 11, marginTop: 6 }}>
        Set the <code>Filter</code> name above to choose a libavfilter filter
        (e.g. <code>scale</code>, <code>trim</code>).
      </div>
    );
  }
  if (AUDIO_ROUTING_FILTERS.has(filter)) {
    return <AudioChannelForm def={def} onChange={onChange} />;
  }
  if (loading) {
    return <div className="empty">Loading {filter} options…</div>;
  }
  if (error) {
    return (
      <div className="empty" style={{ color: '#f5b7b1', fontSize: 11 }}>
        Failed to load {filter}: {error}
      </div>
    );
  }
  if (!info) return null;

  return (
    <>
      <div className="encoder-form-header" style={{ marginTop: 4, marginBottom: 8 }}>
        <strong>{info.name}</strong>
        {info.description && (
          <div className="empty" style={{ fontSize: 11, marginTop: 2 }}>
            {info.description}
          </div>
        )}
      </div>

      {info.options.length === 0 ? (
        <div className="empty" style={{ fontSize: 11 }}>
          This filter has no configurable options.
        </div>
      ) : (
        <>
          {info.options.length > 6 && (
            <input
              type="search"
              placeholder="Search options…"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              style={{ marginBottom: 8 }}
            />
          )}
          {visible.length === 0 && (
            <div className="empty" style={{ fontSize: 11 }}>
              No options match “{search}”.
            </div>
          )}
          {visible.map((opt) => (
            <OptionRow
              key={opt.name}
              filter={info.name}
              option={opt}
              value={getParam(opt.name)}
              onChange={(v) => setParam(opt.name, v)}
              padHints={padHints}
            />
          ))}
        </>
      )}
    </>
  );
}

/* ---------- Model-bearing option name detection ---------- */

/** Returns true for AVOption names that conventionally hold a path to a
 * model or data file: exact matches "model" and "sofa", plus the suffixes
 * "_model" and "_sofa". Mirrors isModelBearingKey in pipeline/filter_model_paths.go. */
function isModelBearingOptionName(name: string): boolean {
  return (
    name === 'model' ||
    name === 'sofa' ||
    name.endsWith('_model') ||
    name.endsWith('_sofa')
  );
}

/* ---------- File-path input for model-bearing options ---------- */

function ModelFileInput({
  value,
  onChange,
}: {
  value: string;
  onChange: (next: string) => void;
}) {
  const [open, setOpen] = useState(false);
  return (
    <>
      <div className="file-field">
        <input
          type="text"
          value={value}
          onChange={(e) => onChange(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') {
              e.preventDefault();
              (e.currentTarget as HTMLInputElement).blur();
            }
          }}
          placeholder="/path/to/model.rnnn"
          title="Filesystem path to the model file (absolute or relative to pipeline file / filter_asset_paths)"
        />
        <button type="button" onClick={() => setOpen(true)} title="Browse local filesystem">
          Browse…
        </button>
      </div>
      <FileBrowser
        open={open}
        mode="open"
        onClose={() => setOpen(false)}
        onPick={(p) => {
          onChange(p);
          setOpen(false);
        }}
      />
    </>
  );
}

/* ---------- Single labelled option row ---------- */

function OptionRow({
  filter,
  option,
  value,
  onChange,
  padHints,
}: {
  filter: string;
  option: FilterOption;
  value: string;
  onChange: (next: string) => void;
  padHints?: Record<string, number>;
}) {
  const range = rangeHint(option);
  const isOverridden = value !== '' && value !== undefined;
  return (
    <div className="filter-option-row">
      <div className="filter-option-name" title={option.name}>
        {isOverridden && <span className="filter-option-modified" aria-label="modified">●</span>}
        {option.name}
      </div>
      {option.help && <div className="filter-option-help">{option.help}</div>}
      <div className="filter-option-control-row">
        <div className="filter-option-control">
          {isModelBearingOptionName(option.name) ? (
            <ModelFileInput value={value} onChange={onChange} />
          ) : (
            <OptionControl filter={filter} option={option} value={value} onChange={onChange} padHints={padHints} />
          )}
        </div>
        {range && <div className="filter-option-range" title="Allowed range">{range}</div>}
      </div>
    </div>
  );
}

/** Format the option's numeric range for display, suppressing libav's
 * common -INF / +INF sentinels (INT_MIN, INT_MAX, FLT_MAX, ...) and
 * normalising endpoints by AVOption type so the formatting itself
 * conveys the type:
 *   - float / double / rational endpoints carry at least one decimal
 *     place (so `0–1` reads as `0.0–1.0`); endpoints with an existing
 *     fractional part are left intact and only the missing side is
 *     normalised.
 *   - integer-typed endpoints render as plain integers (no decimal),
 *     even if libavutil happened to surface them as `1.0`.
 *
 * Returns `''` for enums (the <select> conveys both type and domain),
 * for string-shaped options (no meaningful range), and for options
 * whose min/max are both sentinels. */
function rangeHint(option: FilterOption): string {
  if (Array.isArray(option.constants) && option.constants.length > 0) return '';
  if (
    option.type === 'string' ||
    option.type === 'binary' ||
    option.type === 'dict' ||
    option.type === 'unknown' ||
    option.type === 'bool'
  )
    return '';

  const sane = (n: number | undefined): n is number =>
    typeof n === 'number' && Number.isFinite(n) && Math.abs(n) < 1e15;
  const lo = sane(option.min) ? option.min : undefined;
  const hi = sane(option.max) ? option.max : undefined;
  if (lo === undefined && hi === undefined) return '';

  const isFloat =
    option.type === 'float' || option.type === 'double' || option.type === 'rational';
  const fmt = (n: number): string => {
    if (!isFloat) return String(Math.round(n));
    const s = String(n);
    return s.includes('.') || s.includes('e') || s.includes('E') ? s : `${s}.0`;
  };

  if (lo !== undefined && hi !== undefined) return `${fmt(lo)}–${fmt(hi)}`;
  if (hi !== undefined) return `≤ ${fmt(hi)}`;
  if (lo !== undefined) return `≥ ${fmt(lo)}`;
  return '';
}
