import { useCallback, useEffect, useRef, useState } from 'react';

const RECENT_KEY = 'mm-file-browser-recent';
const RECENT_MAX = 10;

function loadRecent(): string[] {
  try {
    const raw = localStorage.getItem(RECENT_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? (parsed as string[]) : [];
  } catch {
    return [];
  }
}

function pushRecent(path: string): string[] {
  const next = [path, ...loadRecent().filter((p) => p !== path)].slice(0, RECENT_MAX);
  try {
    localStorage.setItem(RECENT_KEY, JSON.stringify(next));
  } catch {
    // storage quota exceeded or unavailable — ignore
  }
  return next;
}

export type BrowseMode = 'open' | 'save';

interface FileEntry {
  name: string;
  path: string;
  is_dir: boolean;
  size?: number;
}

interface ListResponse {
  path: string;
  parent?: string;
  entries: FileEntry[];
  drives?: string[];
  roots?: string[];
}

interface Props {
  open: boolean;
  mode: BrowseMode;
  title?: string;
  /** Optional comma-separated extension filter, e.g. "mp4,mkv,mov". */
  filter?: string;
  /**
   * In save mode: comma-separated list of extensions considered valid output
   * formats. If the typed filename's extension is NOT in this list a warning
   * is shown inline. Does not block saving.
   */
  warnExtensions?: string;
  /** Initial path to seed the browser with. Falls back to $HOME. */
  initialPath?: string;
  /** Default file name when saving. */
  defaultFilename?: string;
  /**
   * Optional hint shown below the filename input in save mode, e.g. to
   * explain that printf-style patterns (shot-%05d.mp4) are supported.
   */
  filenameHint?: string;
  onClose: () => void;
  onPick: (path: string) => void;
}

export function FileBrowser({
  open,
  mode,
  title,
  filter,
  warnExtensions,
  initialPath,
  defaultFilename,
  filenameHint,
  onClose,
  onPick,
}: Props) {
  const [data, setData] = useState<ListResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [pathInput, setPathInput] = useState('');
  const [filename, setFilename] = useState(defaultFilename ?? '');
  const [selected, setSelected] = useState<FileEntry | null>(null);
  // Recent dirs are stored in localStorage and updated on each successful
  // directory navigation. Use a ref-backed state so pushRecent (which
  // writes localStorage) is called exactly once per successful load.
  const [recentDirs, setRecentDirs] = useState<string[]>(() => loadRecent());
  // Track the last path we pushed so we don't double-record the initial load.
  const lastPushedRef = useRef<string | null>(null);

  const load = useCallback(
    async (path: string) => {
      setError(null);
      const params = new URLSearchParams();
      if (path) params.set('path', path);
      if (filter && mode === 'open') params.set('filter', filter);
      try {
        const res = await fetch(`/api/files?${params.toString()}`);
        if (!res.ok) {
          const body = await res.json().catch(() => ({}));
          setError((body as { error?: string }).error ?? `${res.status} ${res.statusText}`);
          return;
        }
        const body = (await res.json()) as ListResponse;
        setData(body);
        setPathInput(body.path);
        setSelected(null);
        // Record every successfully visited directory in the recent list.
        if (lastPushedRef.current !== body.path) {
          lastPushedRef.current = body.path;
          setRecentDirs(pushRecent(body.path));
        }
      } catch (err) {
        setError((err as Error).message);
      }
    },
    [filter, mode],
  );

  useEffect(() => {
    if (!open) return;
    void load(initialPath ?? '');
  }, [open, initialPath, load]);

  const createFolder = useCallback(async () => {
    if (!data) return;
    const name = window.prompt('New folder name:');
    if (!name) return;
    const trimmed = name.trim();
    if (!trimmed || /[\\/]/.test(trimmed) || trimmed === '.' || trimmed === '..') {
      setError('Invalid folder name.');
      return;
    }
    try {
      const res = await fetch('/api/files/mkdir', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ path: data.path, name: trimmed }),
      });
      if (!res.ok) {
        const body = await res.json().catch(() => ({}));
        setError((body as { error?: string }).error ?? `${res.status} ${res.statusText}`);
        return;
      }
      const body = (await res.json()) as { path: string };
      // Refresh the current listing and navigate into the new folder.
      void load(body.path);
    } catch (err) {
      setError((err as Error).message);
    }
  }, [data, load]);

  if (!open) return null;

  const onSelect = (e: FileEntry) => {
    if (e.is_dir) {
      void load(e.path);
      return;
    }
    setSelected(e);
    if (mode === 'save') setFilename(e.name);
  };

  const onConfirm = () => {
    if (mode === 'open') {
      if (selected && !selected.is_dir) {
        onPick(selected.path);
        onClose();
      }
      return;
    }
    // save
    const name = filename.trim();
    if (!name || !data) return;
    onPick(joinPath(data.path, name));
    onClose();
  };

  const canConfirm =
    mode === 'open' ? !!selected && !selected.is_dir : filename.trim() !== '' && !!data;

  return (
    <div className="dialog-overlay" onClick={onClose}>
      <div className="dialog" onClick={(e) => e.stopPropagation()}>
        <div className="dialog-header">
          <h3>{title ?? (mode === 'open' ? 'Open file' : 'Save file as…')}</h3>
          <button onClick={onClose}>×</button>
        </div>

        <div className="file-browser">
          <div className="file-browser-shortcuts">
            {(data?.drives ?? []).length > 0 && (
              <>
                <div className="shortcut-label">Drives</div>
                {data!.drives!.map((d) => (
                  <button key={d} className="shortcut" onClick={() => void load(d)} title={d}>
                    {driveLabel(d)}
                  </button>
                ))}
              </>
            )}
            <div className="shortcut-label">Shortcuts</div>
            {(data?.roots ?? []).map((r) => (
              <button key={r} className="shortcut" onClick={() => void load(r)} title={r}>
                {shortcutLabel(r)}
              </button>
            ))}
            {recentDirs.length > 0 && (
              <>
                <div className="shortcut-label">Recent</div>
                {recentDirs.map((r) => (
                  <button key={r} className="shortcut shortcut-recent" onClick={() => void load(r)} title={r}>
                    {shortcutLabel(r)}
                  </button>
                ))}
              </>
            )}
          </div>

          <div className="file-browser-main">
            <div className="file-browser-pathbar">
              <button
                onClick={() => data?.parent && void load(data.parent)}
                disabled={!data?.parent}
                title="Up one directory"
              >
                ↑
              </button>
              <input
                type="text"
                value={pathInput}
                onChange={(e) => setPathInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') void load(pathInput);
                }}
                placeholder="/path/to/folder"
              />
              <button onClick={() => void load(pathInput)}>Go</button>
              {mode === 'save' && (
                <button
                  onClick={() => void createFolder()}
                  disabled={!data}
                  title="Create a new folder inside the current directory"
                >
                  New folder
                </button>
              )}
            </div>

            {error && <div className="file-browser-error">{error}</div>}

            <div className="file-browser-list">
              {data?.entries.length === 0 && <div className="empty">Empty folder.</div>}
              {data?.entries.map((e) => (
                <div
                  key={e.path}
                  className={`file-row ${selected?.path === e.path ? 'selected' : ''}`}
                  onClick={() => onSelect(e)}
                  onDoubleClick={() => {
                    if (e.is_dir) void load(e.path);
                    else {
                      onPick(e.path);
                      onClose();
                    }
                  }}
                >
                  <span className="file-icon">{e.is_dir ? '📁' : '🎬'}</span>
                  <span className="file-name">{e.name}</span>
                  {!e.is_dir && <span className="file-size">{formatSize(e.size ?? 0)}</span>}
                </div>
              ))}
            </div>

            {mode === 'save' && (
              <div className="file-browser-savebar">
                <label>File name</label>
                <input
                  type="text"
                  value={filename}
                  onChange={(e) => setFilename(e.target.value)}
                  placeholder="output.mp4"
                />
                {warnExtensions && (() => {
                  const name = filename.trim();
                  if (!name) return null;
                  const dot = name.lastIndexOf('.');
                  if (dot < 0) return (
                    <div className="file-browser-ext-warn">
                      ⚠ No file extension — a file extension is needed to select the right muxer.
                    </div>
                  );
                  // Strip printf-style placeholders (e.g. %05d, %s) before
                  // checking the extension so patterns like shot-%05d.mp4
                  // are evaluated as "mp4", not "%05d.mp4" or similar.
                  const ext = name.slice(dot + 1).replace(/%[0-9]*[diouxXeEfgGcs]/g, '').toLowerCase();
                  const allowed = new Set(warnExtensions.split(',').map((s) => s.trim().toLowerCase()));
                  if (!allowed.has(ext)) return (
                    <div className="file-browser-ext-warn">
                      ⚠ <strong>.{ext}</strong> is not a recognised media container — this job will likely fail when run.
                    </div>
                  );
                  return null;
                })()}
                {filenameHint && (
                  <div className="file-browser-filename-hint">
                    {filenameHint}
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        <div className="dialog-footer">
          <span className="hint">
            {mode === 'open'
              ? 'Double-click a file to open, or select it and click Open.'
              : filenameHint
                ? 'Navigate to the output folder, type a filename or pattern, and click Save.'
                : 'Pick a folder, type a filename, and click Save.'}
          </span>
          <div className="spacer" />
          <button onClick={onClose}>Cancel</button>
          <button className="primary" disabled={!canConfirm} onClick={onConfirm}>
            {mode === 'open' ? 'Open' : 'Save'}
          </button>
        </div>
      </div>
    </div>
  );
}

function joinPath(dir: string, name: string): string {
  if (dir.endsWith('/')) return dir + name;
  return dir + '/' + name;
}

function shortcutLabel(p: string): string {
  if (p === '/') return '/ (root)';
  // Show the trailing path component but keep enough context. Split on
  // both separators so Windows paths ("C:\\Users\\Tom") render the same
  // way as POSIX paths.
  const parts = p.split(/[\\/]/).filter(Boolean);
  if (parts.length === 0) return p;
  return parts[parts.length - 1] || p;
}

// driveLabel formats a Windows drive-root path ("C:\\", "E:\\") for the
// drives shortcut group. We strip the trailing separator so the button
// reads "C:" rather than "C:\\", which matches how Windows Explorer
// labels its sidebar entries.
function driveLabel(p: string): string {
  return p.replace(/[\\/]+$/, '');
}

function formatSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  if (bytes < 1024 * 1024 * 1024) return `${(bytes / 1024 / 1024).toFixed(1)} MB`;
  return `${(bytes / 1024 / 1024 / 1024).toFixed(2)} GB`;
}
