// useJobRun: starts a pipeline run via /api/run, subscribes to its SSE stream,
// surfaces state/metrics/errors/logs, and exposes a cancel function.

import { useCallback, useEffect, useRef, useState } from 'react';
import type { JobConfig } from './jobTypes';
import type { BackendSettings } from './backendSettings';

export type JobStatus = 'idle' | 'starting' | 'running' | 'succeeded' | 'failed' | 'canceled';

export interface NodeMetric {
  NodeID: string;
  Frames: number;
  Errors: number;
  Bytes: number;
  FPS: number;
  Elapsed: number;       // ns
  AvgLatency: number;    // ns
  MaxLatency: number;    // ns
  MediaPTS: number;      // ns — latest input timestamp processed (source nodes only)
  MediaDuration: number; // ns — total input duration (0 = live / unknown)
  OutputPTS: number;     // ns — latest output timestamp written (sink nodes only)
}

// NodePerfSnapshot mirrors pipeline/snap.NodePerfSnapshot.
export interface NodePerfSnapshot {
  NodeID: string;
  FPS: number;
  FPSTarget: number;
  FPSDeficit: number;
  ActiveFrac: number;
  IdleFrac: number;
  StalledFrac: number;
  StallCount: number;
  MaxStallDuration: number; // ns
  QueueFillFrac: number;
  Elapsed: number;          // ns
  ThreadsConfigured: number;
  ThreadMode: string;
  ThreadsBusy: number;
  EstimatedCPUCores: number;
  FrameLatencyMean: number; // ns (EWMA)
  ThreadRestarts: number;
  CodecName?: string;
  CurrentPreset?: string;
  PresetLadder?: string[];
  PresetIndex?: number;
  PresetSwitches?: number;
  PresetLocked?: boolean;
}

// DecisionRecord mirrors pipeline/snap.DecisionRecord.
export interface DecisionRecord {
  time: string;    // RFC3339
  node: string;
  action: string;
  from?: string;
  to?: string;
  deficit?: number;
  reason?: string;
}

// RealtimeSnapshot mirrors pipeline/snap.RealtimeSnapshot.
export interface RealtimeSnapshot {
  Enabled?: boolean;
  FPSTarget?: number;
  FPSActual?: number;
  Satisfied?: boolean;
  Decisions?: DecisionRecord[];
}

export interface MetricsSnapshot {
  State: string;
  Elapsed: number;
  Nodes: NodeMetric[];
  // Aggregated across all source nodes — see pipeline.MetricsSnapshot.
  MediaPTS: number;      // ns
  MediaDuration: number; // ns (0 = live / unknown)
  OutputPTS: number;     // ns — aggregated across sink nodes (max)
  Perf: NodePerfSnapshot[];
  Realtime?: RealtimeSnapshot;
}

export interface NodeError {
  node_id: string;
  stage: string;
  error: string;
  time_ms: number;
}

export interface LogEntry {
  time_ms: number;
  message: string;
  level?: 'info' | 'warn' | 'error';
  replaceKey?: string; // when set, replaces the last entry with the same key
}

export interface RunState {
  jobId: string | null;
  status: JobStatus;
  pipelineState: string;     // last reported pipeline state ("Playing", etc.)
  metrics: MetricsSnapshot | null;
  errors: NodeError[];       // accumulated per-node errors
  logs: LogEntry[];          // bounded log history
  finalError: string | null;
  start: () => Promise<void>;
  cancel: () => Promise<void>;
  reset: () => void;
}

const LOG_CAP = 200;
const ERR_CAP = 50;

export function useJobRun(getConfig: () => JobConfig | null, backend?: BackendSettings | null): RunState {
  const [jobId, setJobId] = useState<string | null>(null);
  const [status, setStatus] = useState<JobStatus>('idle');
  const [pipelineState, setPipelineState] = useState<string>('');
  const [metrics, setMetrics] = useState<MetricsSnapshot | null>(null);
  const [errors, setErrors] = useState<NodeError[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [finalError, setFinalError] = useState<string | null>(null);
  const esRef = useRef<EventSource | null>(null);

  const closeStream = useCallback(() => {
    esRef.current?.close();
    esRef.current = null;
  }, []);

  const reset = useCallback(() => {
    closeStream();
    setJobId(null);
    setStatus('idle');
    setPipelineState('');
    setMetrics(null);
    setErrors([]);
    setLogs([]);
    setFinalError(null);
  }, [closeStream]);

  const start = useCallback(async () => {
    const cfg = getConfig();
    if (!cfg) return;
    reset();
    setStatus('starting');

    let id: string;
    try {
      const headers: Record<string, string> = { 'Content-Type': 'application/json' };
      let url: string;
      if (backend?.url) {
        url = `${backend.url}/v1/jobs`;
        if (backend.token) headers['Authorization'] = `Bearer ${backend.token}`;
      } else {
        url = '/api/run';
      }
      const res = await fetch(url, {
        method: 'POST',
        headers,
        body: JSON.stringify(cfg),
      });
      if (!res.ok) {
        const err = await safeError(res);
        setStatus('failed');
        setFinalError(err);
        return;
      }
      if (backend?.url) {
        const body = (await res.json()) as { id: string };
        id = body.id;
      } else {
        const body = (await res.json()) as { job_id: string };
        id = body.job_id;
      }
    } catch (err) {
      setStatus('failed');
      setFinalError((err as Error).message);
      return;
    }

    setJobId(id);
    setStatus('running');

    // EventSource cannot set custom headers; pass token as query param for remote.
    let eventsUrl: string;
    if (backend?.url) {
      eventsUrl = `${backend.url}/v1/jobs/${id}/events`;
      if (backend.token) eventsUrl += `?token=${encodeURIComponent(backend.token)}`;
    } else {
      eventsUrl = `/api/events/${id}`;
    }
    const es = new EventSource(eventsUrl);
    esRef.current = es;

    es.addEventListener('state', (ev: MessageEvent) => {
      const data = parseEvent<{ from: string; to: string }>(ev);
      if (data?.to) setPipelineState(data.to);
    });
    es.addEventListener('metrics', (ev: MessageEvent) => {
      const snap = parseEvent<MetricsSnapshot>(ev);
      if (snap) setMetrics(snap);
    });
    es.addEventListener('error', (ev: MessageEvent) => {
      const data = parseEvent<{ node_id: string; stage: string; error: string; time_ms: number }>(ev);
      if (!data) return;
      setErrors((arr) => {
        const next = [...arr, data];
        return next.length > ERR_CAP ? next.slice(next.length - ERR_CAP) : next;
      });
      setLogs((l) => trimLog(l, { time_ms: data.time_ms, message: `[${data.node_id}] ${data.error}`, level: 'error' }));
    });
    es.addEventListener('log', (ev: MessageEvent) => {
      const data = parseEvent<{ message?: string; time_ms: number }>(ev);
      if (data?.message) setLogs((l) => trimLog(l, { time_ms: data.time_ms, message: data.message! }));
    });
    es.addEventListener('metadata', (ev: MessageEvent) => {
      const data = parseEvent<{
        node_id: string;
        time_ms: number;
        metadata?: {
          file_path?: string;
          progress?: boolean;
          custom?: { twelvelabs?: Record<string, unknown>; message?: string };
        };
      }>(ev);
      if (!data) return;

      // Generic progress metadata (e.g. sequence_editor render progress): surface
      // the message as a single, in-place-updating log line per node.
      const progressMsg = data.metadata?.custom?.message;
      if (progressMsg && !data.metadata?.custom?.twelvelabs) {
        setLogs((l) => trimLog(l, {
          time_ms: data.time_ms,
          message: `[${data.node_id}] ${progressMsg}`,
          replaceKey: `progress:${data.node_id}`,
        }));
        return;
      }

      const tl = data.metadata?.custom?.twelvelabs;
      if (!tl) return;
      const event = String(tl['event'] ?? '');
      const filePath = String(tl['file_path'] ?? data.metadata?.file_path ?? '');
      const taskId = tl['task_id'] ? ` task=${tl['task_id']}` : '';
      const videoId = tl['video_id'] ? ` video=${tl['video_id']}` : '';
      const errMsg = tl['error'] ? ` error=${tl['error']}` : '';
      const fileLabel = filePath ? ` ${filePath}` : '';
      const level: LogEntry['level'] = event === 'error' ? 'error' : 'info';

      if (event === 'upload_progress') {
        const sent = Number(tl['sent_bytes'] ?? 0);
        const total = Number(tl['total_bytes'] ?? 0);
        const pct = Number(tl['pct'] ?? 0);
        const sentMB = (sent / 1_048_576).toFixed(1);
        const totalMB = total > 0 ? ` / ${(total / 1_048_576).toFixed(1)} MB` : '';
        const msg = `[${data.node_id}] uploading ${pct}% (${sentMB} MB${totalMB})`;
        setLogs((l) => trimLog(l, { time_ms: data.time_ms, message: msg, level, replaceKey: `upload:${data.node_id}` }));
        return;
      }

      if (event === 'task_status') {
        const status = String(tl['status'] ?? '');
        const msg = `[${data.node_id}] indexing${taskId} status=${status}`;
        setLogs((l) => trimLog(l, { time_ms: data.time_ms, message: msg, level, replaceKey: `wait:${data.node_id}` }));
        return;
      }

      const status = tl['status'] ? ` status=${tl['status']}` : '';
      const msg = `[${data.node_id}] ${event}${fileLabel}${taskId}${videoId}${status}${errMsg}`;
      setLogs((l) => trimLog(l, { time_ms: data.time_ms, message: msg, level }));
    });
    es.addEventListener('done', (ev: MessageEvent) => {
      const data = parseEvent<{ status: JobStatus; error: string }>(ev);
      if (data) {
        setStatus(data.status);
        if (data.error) setFinalError(data.error);
      }
      closeStream();
    });

    es.onerror = () => {
      // Browser will auto-retry; if the job is finished the server closes the
      // stream cleanly which surfaces here too. Keep status unchanged.
    };
  }, [getConfig, reset, closeStream]);

  const cancel = useCallback(async () => {
    if (!jobId) return;
    try {
      if (backend?.url) {
        const headers: Record<string, string> = {};
        if (backend.token) headers['Authorization'] = `Bearer ${backend.token}`;
        await fetch(`${backend.url}/v1/jobs/${jobId}`, { method: 'DELETE', headers });
      } else {
        await fetch(`/api/cancel/${jobId}`, { method: 'POST' });
      }
    } catch {
      /* ignore */
    }
  }, [jobId, backend]);

  // Cleanup on unmount.
  useEffect(() => () => closeStream(), [closeStream]);

  return {
    jobId,
    status,
    pipelineState,
    metrics,
    errors,
    logs,
    finalError,
    start,
    cancel,
    reset,
  };
}

function parseEvent<T>(ev: MessageEvent): T | null {
  try {
    const wrapped = JSON.parse(ev.data) as { type: string; time_ms: number; data: T };
    // The server wraps payloads in {type, time_ms, data}; surface the inner data
    // for typed listeners but also propagate time_ms by merging when relevant.
    if (wrapped && typeof wrapped === 'object' && 'data' in wrapped) {
      const merged = wrapped.data as unknown as Record<string, unknown>;
      if (merged && typeof merged === 'object' && !('time_ms' in merged)) {
        merged.time_ms = wrapped.time_ms;
      }
      return wrapped.data;
    }
    return null;
  } catch {
    return null;
  }
}

function trimLog(arr: LogEntry[], next: LogEntry): LogEntry[] {
  let base = arr;
  if (next.replaceKey) {
    const idx = [...arr].reverse().findIndex((e: LogEntry) => e.replaceKey === next.replaceKey);
    if (idx !== -1) {
      const realIdx = arr.length - 1 - idx;
      base = [...arr.slice(0, realIdx), ...arr.slice(realIdx + 1)];
    }
  }
  const out = [...base, next];
  return out.length > LOG_CAP ? out.slice(out.length - LOG_CAP) : out;
}

async function safeError(res: Response): Promise<string> {
  try {
    const body = await res.json();
    if (body && typeof body === 'object' && 'error' in body) return String((body as { error: string }).error);
  } catch {
    /* fall through */
  }
  return `${res.status} ${res.statusText}`;
}
